VALUES
  ('social-worker-moex-01351', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '某家庭的主要照顧者突然死亡導致家庭功能受損，頓時陷入困境。如選擇使用危機干預的工作模 式來協助，下列何者不是該模式的工作方法？', '["為解決突發事件，應快速辨識問題，暫不處理案家感受及情緒", "因應實務運作之所需，採取折衷取向來進行危機干預", "考量案家的安全性與需求，進行心理社會評量（assessment）", "運用同理與支持，讓案主在混亂中仍保有自我控制感"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "e697d89d6b44", "answer_pdf_sha1": "6638e1fe6f90", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01352', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '對於復原力（resilience）的敘述，下列何者錯誤？', '["復原力是針對負面生活情況的改變或調適能力", "復原力是一個動態歷程，不是一個終點", "「文化」是影響復原力的關鍵因素之一", "復原力是一組固定特質或能力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "e697d89d6b44", "answer_pdf_sha1": "6638e1fe6f90", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01353', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會個案工作中所稱的「契約」（contract）比較接近一種「行動承諾」，對於「契約」的敘述， 下列何者錯誤？', '["是社會工作者與案主對於目標和行動計畫的共同認可", "落實契約是社會工作責信的具體表現之一", "契約中需說明或釐清社會工作者與案主的角色", "因契約具有法律效力，所以不需要案主的同意"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "e697d89d6b44", "answer_pdf_sha1": "6638e1fe6f90", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01354', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會個案工作者通常會將處遇目標再延伸出明確可操作的階段性子目標。關於子目標具體化的敘 述，下列何者正確？', '["為避免破壞工作關係，不宜監控子目標達成成效", "為降低不必要的探索歷程，不宜接受案主提出的子目標", "為避免案主不配合，不宜訂定子目標的完成時間", "為降低案主的挫折感，不宜提出不可行的子目標"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "e697d89d6b44", "answer_pdf_sha1": "6638e1fe6f90", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01355', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關家系圖的敘述，下列何者正確？', '["能夠描述案主社會參與狀態", "能夠了解案主過去的求助史", "能呈現案主家庭的親子關係", "能評估案主家庭的物理環境"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "e697d89d6b44", "answer_pdf_sha1": "6638e1fe6f90", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01356', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關社會個案工作處遇目標的敘述，下列何者正確？', '["處遇目標是由社會工作者設定的問題解決方向與目的", "內隱的處遇目標因為看不到，無法具體化呈現，例如負向思考或是內在感受", "外顯的處遇目標可以透過觀察確認是否產生變化，例如個人行為資源補充等", "非自願（強制性）案主的處遇目標不需要經過案主與社會工作者協商機制來設定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "e697d89d6b44", "answer_pdf_sha1": "6638e1fe6f90", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01357', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關接案與開案的相關敘述，下列何者正確？', '["開案的先決條件是案主的待助問題必須要能符合開案指標", "開案的時候依據個案的先來後到，排定個案服務優先順序", "在接案會談時，必須要對案主的問題有明確的處遇目的和完成的時間表", "在接案會談時，要和案主討論在服務過程中學到處理目前生活困境的方法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "e697d89d6b44", "answer_pdf_sha1": "6638e1fe6f90", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01358', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關家庭評估與家庭處遇的敘述，下列何者正確？', '["只需要評估家庭結構的情況，就可以了解家庭的資源運用狀態並進行處遇", "若能促進家庭持續性成長就能使家庭確認自己的優點，但多數家庭都做不到", "家庭決策是指家庭成員之間在未經批判之下所共同接受、相信的認知", "家庭中發生的壓力事件容易造成家庭成員的角色功能變化，以便保持家庭平衡"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "e697d89d6b44", "answer_pdf_sha1": "6638e1fe6f90", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01359', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關社會工作者必須撰寫個案紀錄的敘述，下列何者正確？', '["為了證明責信", "為了保守秘密", "是不必要的工作", "可用判斷性字詞"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "e697d89d6b44", "answer_pdf_sha1": "6638e1fe6f90", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01360', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關專業關係的說法，下列何者正確？①社會工作者擁有專業證照無助於專業權威的說服力', '["社會工作者常用避免案主參與處遇過程來操控處遇方式", "社會工作者與案主的專業關係受 其生活的社會文化脈絡影響", "社會工作者的評斷態度可能是案主產生抗拒的多元因素之一 ⑤社會工作者的個人特質是促進專業關係建立的助力之一", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "e697d89d6b44", "answer_pdf_sha1": "6638e1fe6f90", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
